   212→    /**
   213→     * 注入网络请求Hook，用于捕获动态生成的PDF URL
   214→     */
   215→    private fun injectNetworkHooks() {
   216→        val hookJs = """
   217→            (function() {
   218→                // Hook XMLHttpRequest
   219→                var originalOpen = XMLHttpRequest.prototype.open;
   220→                var originalSend = XMLHttpRequest.prototype.send;
   221→
   222→                XMLHttpRequest.prototype.open = function(method, url, ...args) {
   223→                    this._courtUrl = url;
   224→                    return originalOpen.apply(this, [method, url, ...args]);
   225→                };
   226→
   227→                XMLHttpRequest.prototype.send = function(body) {
   228→                    if (this._courtUrl && this._courtUrl.indexOf('pdf') !== -1) {
   229→                        console.log('[XHRLoad]', this._courtUrl);
   230→                    }
   231→                    return originalSend.apply(this, [body]);
   232→                };
   233→
   234→                // Hook fetch
   235→                var originalFetch = window.fetch;
   236→                window.fetch = function(url, ...args) {
   237→                    if (typeof url === 'string' && url.indexOf('pdf') !== -1) {
   238→                        console.log('[FetchLoad]', url);
   239→                    }
   240→                    return originalFetch.apply(this, [url, ...args]);
   241→                };
   242→
   243→                // 监听DOM变化，捕获动态添加的元素
   244→                var observer = new MutationObserver(function(mutations) {
   245→                    mutations.forEach(function(mutation) {
   246→                        mutation.addedNodes.forEach(function(node) {
   247→                            if (node.nodeType === 1) {
   248→                                var text = node.textContent || '';
   249→                                if (text.indexOf('.pdf') !== -1 || /传票|举证|受理|通知书/.test(text)) {
   250→                                    console.log('[NewNode]', text.substring(0, 50));
   251→                                }
   252→                            }
   253→                        });
   254→                    });
   255→                });
   256→
   257→                observer.observe(document.body || document.documentElement, {
   258→                    childList: true,
   259→                    subtree: true
   260→                });
   261→
   262→                console.log('[CourtHooks] Network hooks installed');
   263→            })();
   264→        """
   265→        webView.evaluateJavascript(hookJs, null)
   266→    }
