   272→    private fun startAutoScan() {
   273→        val timeout = 60000L // 60秒超时
   274→        val startTime = System.currentTimeMillis()
   275→
   276→        scanRunnable = object : Runnable {
   277→            override fun run() {
   278→                val elapsed = System.currentTimeMillis() - startTime
   279→                if (elapsed > timeout) {
   280→                    Log.d(TAG, "Auto scan timeout")
   281→                    handler.removeCallbacks(this)
   282→                    finishOnUiThread()
   283→                    return
   284→                }
   285→
   286→                // 每2秒扫描一次
   287→                scanAndDownloadPdfs()
   288→                handler.postDelayed(this, 2000)
   289→            }
   290→        }
   291→        handler.post(scanRunnable!!)
   292→    }
