   294→    /**
   295→     * 扫描页面并自动点击PDF按钮
   296→     * 针对法院送达页面优化：PDF文件名本身就是按钮
   297→     * 必须通过点击触发下载，URL隐藏在JavaScript中
   298→     */
   299→    private fun scanAndDownloadPdfs() {
   300→        val js = """
   301→            (function() {
   302→                try {
   303→                    var clickedCount = 0;
   304→                    var totalFound = 0;
   305→
   306→                    // 1. 首先查找包含PDF文件名的按钮/卡片
   307→                    // 法院送达页面的特点：按钮文字就是PDF文件名
   308→                    var allElements = document.querySelectorAll('*');
   309→                    var pdfButtons = [];
   310→
   311→                    for (var i = 0; i < allElements.length; i++) {
   312→                        var el = allElements[i];
   313→                        var text = (el.textContent || el.innerText || '').trim();
   314→                        var classNames = el.className || '';
   315→                        var tagName = el.tagName?.toLowerCase() || '';
   316→
   317→                        // 查找包含PDF文件名的元素
   318→                        // 文件名格式：xxx（xxx）.pdf 或 xxx.pdf
   319→                        var isPdfFile = /\.pdf\s*$$/i.test(text) ||
   320→                                       /（.+）\.pdf/i.test(text) ||
   321→                                       /传票|举证通知书|受理案件通知书|判决书|裁定书|应诉通知书/.test(text);
   322→
   323→                        // 必须是可点击元素且有合适的类名
   324→                        var isClickable = tagName === 'button' ||
   325→                                         tagName === 'a' ||
   326→                                         classNames.indexOf('btn') !== -1 ||
   327→                                         classNames.indexOf('card') !== -1 ||
   328→                                         classNames.indexOf('item') !== -1 ||
   329→                                         classNames.indexOf('list') !== -1 ||
   330→                                         el.onclick !== null;
   331→
   332→                        if (isPdfFile && isClickable && text.length > 5 && text.length < 100) {
   333→                            // 检查是否已经在列表中
   334→                            var alreadyFound = false;
   335→                            for (var j = 0; j < pdfButtons.length; j++) {
   336→                                if (pdfButtons[j].text === text) {
   337→                                    alreadyFound = true;
   338→                                    break;
   339→                                }
   340→                            }
   341→                            if (!alreadyFound) {
   342→                                pdfButtons.push({
   343→                                    element: el,
   344→                                    text: text,
   345→                                    className: classNames,
   346→                                    tagName: tagName
   347→                                });
   348→                            }
   349→                        }
   350→                    }
   351→
   352→                    totalFound = pdfButtons.length;
   353→
   354→                    // 2. 自动点击每个PDF按钮
   355→                    for (var k = 0; k < pdfButtons.length; k++) {
   356→                        (function(btn) {
   357→                            setTimeout(function() {
   358→                                try {
   359→                                    // 尝试多种点击方式
   360→                                    if (btn.element.click) {
   361→                                        btn.element.click();
   362→                                    } else if (document.createEvent) {
   363→                                        var evt = document.createEvent('MouseEvents');
   364→                                        evt.initMouseEvent('click', true, true, window, 0, 0, 0, 0, 0, false, false, false, false, 0, null);
   365→                                        btn.element.dispatchEvent(evt);
   366→                                    }
   367→
   368→                                    // 添加视觉反馈
   369→                                    if (btn.element.style) {
   370→                                        var originalBg = btn.element.style.backgroundColor;
   371→                                        btn.element.style.backgroundColor = '#4CAF50';
   372→                                        setTimeout(function() {
   373→                                            btn.element.style.backgroundColor = originalBg;
   374→                                        }, 500);
   375→                                    }
   376→
   377→                                    clickedCount++;
   378→                                } catch(e) {
   379→                                    console.log('Click error: ' + e.message);
   380→                                }
   381→                            }, k * 1000); // 每个按钮间隔1秒点击
   382→                        })(pdfButtons[k]);
   383→                    }
   384→
   385→                    return JSON.stringify({
   386→                        count: totalFound,
   387→                        clicked: 'scheduled',
   388→                        buttons: pdfButtons.map(function(b) { return { text: b.text, tag: b.tagName }; })
   389→                    });
   390→                } catch(e) {
   391→                    return JSON.stringify({error: e.message});
   392→                }
   393→            })();
   394→        """
   395→
   396→        webView.evaluateJavascript(js) { result ->
   397→            Log.d(TAG, "Scan and click result: $result")
   398→            if (result != null && result != "null" && !result.contains("\"error\"")) {
   399→                handleScanClickResult(result)
   400→            }
   401→        }
   402→    }
