   404→    /**
   405→     * 处理扫描点击结果
   406→     */
   407→    private fun handleScanClickResult(jsonResult: String) {
   408→        try {
   409→            val countPattern = Regex(""""count"\s*:\s*(\d+)""")
   410→            val countMatch = countPattern.find(jsonResult)
   411→
   412→            if (countMatch != null) {
   413→                val count = countMatch.groupValues[1].toIntOrNull() ?: 0
   414→                if (count > 0) {
   415→                    Log.d(TAG, "Found and will click $count PDF buttons")
   416→                    handler.post {
   417→                        tvScanningStatus.text = "发现 $count 个文档，正在自动下载..."
   418→                    }
   419→
   420→                    // 等待所有点击完成后再关闭
   421→                    handler.postDelayed({
   422→                        finishOnUiThread()
   423→                    }, (count * 1000 + 5000).toLong()) // 每个按钮1秒 + 额外5秒缓冲
   424→                }
   425→            }
   426→        } catch (e: Exception) {
   427→            Log.e(TAG, "Error parsing scan click result", e)
   428→        }
   429→    }
