   431→    /**
   432→     * 处理扫描结果并自动下载
   433→     */
   434→    private fun handleScanResult(jsonResult: String) {
   435→        try {
   436→            // 清理JSON字符串
   437→            val cleaned = jsonResult
   438→                .replace("\\u003C", "<")
   439→                .replace("\\u003E", ">")
   440→                .replace("\\\"", "\"")
   441→                .replace("\\/", "/")
   442→
   443→            // 提取所有url字段
   444→            val urlPattern = Regex(""""url"\s*:\s*"([^"]+)"""")
   445→            val textPattern = Regex(""""text"\s*:\s*"([^"]+)""""")
   446→
   447→            val urls = urlPattern.findAll(cleaned).map { it.groupValues[1] }.toList()
   448→            val texts = textPattern.findAll(cleaned).map { it.groupValues[1] }.toList()
   449→
   450→            if (urls.isNotEmpty()) {
   451→                Log.d(TAG, "Found ${urls.size} potential PDF links")
   452→
   453→                for (i in urls.indices) {
   454→                    val pdfUrl = urls[i].trim()
   455→                    val displayName = if (i < texts.size) texts[i].trim() else "文档"
   456→
   457→                    // 去重
   458→                    if (!foundPdfs.contains(pdfUrl) && pdfUrl.isNotEmpty() && pdfUrl != "vue-state-detected") {
   459→                        foundPdfs.add(pdfUrl)
   460→                        Log.d(TAG, "New PDF found: $pdfUrl - $displayName")
   461→
   462→                        // 自动下载
   463→                        if (autoMode) {
   464→                            tvScanningStatus.text = "发现文档: $displayName\n正在下载..."
   465→                            lifecycleScope.launch {
   466→                                delay(500) // 避免同时发起太多请求
   467→                                downloadAndSavePdf(pdfUrl, displayName)
   468→                            }
   469→                        }
   470→                    }
   471→                }
   472→
   473→                if (foundPdfs.isNotEmpty() && autoMode) {
   474→                    tvCardCount()?.text = "已发现 ${foundPdfs.size} 个文档"
   475→                    btnCloseOverlay()?.visibility = View.VISIBLE
   476→                }
   477→            }
   478→        } catch (e: Exception) {
   479→            Log.e(TAG, "Error parsing scan result", e)
   480→        }
   481→    }
