   483→    /**
   484→     * 处理PDF下载请求（从拦截或下载监听器）
   485→     */
   486→    private fun handlePdfDownload(downloadUrl: String) {
   487→        if (!foundPdfs.contains(downloadUrl)) {
   488→            foundPdfs.add(downloadUrl)
   489→            Log.d(TAG, "PDF download intercepted: $downloadUrl")
   490→
   491→            lifecycleScope.launch {
   492→                downloadAndSavePdf(downloadUrl, "文档")
   493→            }
   494→        }
   495→    }
