   497→    /**
   498→     * 下载PDF并保存到数据库
   499→     */
   500→    private suspend fun downloadAndSavePdf(rawUrl: String, displayName: String) {
   501→        with(kotlinx.coroutines.Dispatchers.IO) {
   502→            try {
   503→                val resolvedUrl = resolveUrl(rawUrl)
   504→                Log.d(TAG, "Downloading: $resolvedUrl")
   505→
   506→                val file = downloadPdfFile(resolvedUrl)
   507→                if (file != null && file.exists()) {
   508→                    // 保存到数据库
   509→                    val fileName = extractFileName(rawUrl, displayName)
   510→                    val docRecord = DocumentRecord(
   511→                        smsId = smsId,
   512→                        fileName = fileName,
   513→                        filePath = file.absolutePath,
   514→                        fileSize = file.length(),
   515→                        sourceUrl = resolvedUrl,
   516→                        downloadTime = System.currentTimeMillis(),
   517→                        parseStatus = 0, // 待识别
   518→                        displayName = displayName
   519→                    )
   520→
   521→                    val insertedId = db.documentDao().insert(docRecord)
   522→                    Log.d(TAG, "Document saved to DB: id=$insertedId, file=$fileName")
   523→
   524→                    // 触发PDF解析和日历同步
   525→                    com.shanfuchun.courtassistant.service.PdfParser.parseAndSync(
   526→                        this@WebViewActivity, db, insertedId
   527→                    )
   528→
   529→                    // 更新UI
   530→                    handler.post {
   531→                        tvScanningStatus.text = "下载成功: $fileName"
   532→                    }
   533→
   534→                    // 如果有原始docId（来自待下载记录），更新它
   535→                    if (docId > 0) {
   536→                        val oldDoc = db.documentDao().getById(docId)
   537→                        if (oldDoc != null) {
   538→                            // 合并信息到新记录后删除旧记录
   539→                            db.documentDao().delete(oldDoc)
   540→                        } else {
   541→                            // oldDoc is null, do nothing
   542→                        }
   543→                    }
   544→                } else {
   545→                    Log.e(TAG, "Download failed: $resolvedUrl")
   546→                    handler.post {
   547→                        tvScanningStatus.text = "下载失败: $displayName"
   548→                    }
   549→                }
   550→            } catch (e: Exception) {
   551→                Log.e(TAG, "Error in downloadAndSavePdf", e)
   552→                handler.post {
   553→                    tvScanningStatus.text = "下载出错: ${e.message}"
   554→                }
   555→            }
   556→        }
   557→    }
